            textSize = 16f
            setPadding(0, 0, 0, 16)
        }

        imageContainer = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
        }

        rootLayout.addView(statusTextView)
        rootLayout.addView(contentTextView)
        rootLayout.addView(imageContainer)
        scrollView.addView(rootLayout)
        setContentView(scrollView)

        handleIncomingIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIncomingIntent(intent)
    }

    private fun handleIncomingIntent(intent: Intent) {
        when {
            intent.action == Intent.ACTION_SEND && intent.type != null -> {
                when {
                    intent.type == "text/plain" -> handleSharedText(intent)
                    intent.type?.startsWith("image/") == true -> handleSharedImage(intent)
                    else -> {
                        showError("Unsupported content type: ${intent.type}")
                    }
                }
            }
            intent.action == Intent.ACTION_SEND_MULTIPLE && intent.type?.startsWith("image/") == true -> {
                handleSharedMultipleImages(intent)
            }
            else -> {
                showError("Unsupported intent action: ${intent.action}")
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        val sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT)

        if (sharedText.isNullOrEmpty()) {
            showError("No text content received")
            return
        }

        Log.d(TAG, "Received shared text: $sharedText")

        val urls = extractUrls(sharedText)

        val displayBuilder = StringBuilder()

        if (!sharedSubject.isNullOrEmpty()) {
            displayBuilder.appendLine("Subject: $sharedSubject")
            displayBuilder.appendLine()
        }

        displayBuilder.appendLine("Shared Text:")
        displayBuilder.appendLine(sharedText)

        if (urls.isNotEmpty()) {
            displayBuilder.appendLine()
            displayBuilder.appendLine("Extracted URLs (${urls.size}):")
            urls.forEachIndexed { index, url ->
                displayBuilder.appendLine("${index + 1}. $url")
            }
            processUrls(urls)
        }

        statusTextView.text = if (urls.isNotEmpty()) {
            "URL Shared (${urls.size} found)"
        } else {
            "Text Shared"
        }

        contentTextView.text = displayBuilder.toString()

        Toast.makeText(this, "Text content received", Toast.LENGTH_SHORT).show()
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri: Uri? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableExtra(Intent.EXTRA_STREAM)
        }

        if (imageUri == null) {
            showError("No image received")
            return
        }

        Log.d(TAG, "Received shared image: $imageUri")

        statusTextView.text = "Image Shared"
        contentTextView.text = "Image URI: $imageUri"

        processAndDisplayImage(imageUri)

        Toast.makeText(this, "Image received", Toast.LENGTH_SHORT).show()
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris: ArrayList<Uri>? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        }

        if (imageUris.isNullOrEmpty()) {
            showError("No images received")
            return
        }

        Log.d(TAG, "Received ${imageUris.size} shared images")

        statusTextView.text = "Multiple Images Shared (${imageUris.size})"

        val uriInfo = StringBuilder("Image URIs:\n")
        imageUris.forEachIndexed { index, uri ->
            uriInfo.appendLine("${index + 1}. $uri")
        }
        contentTextView.text = uriInfo.toString()

        imageUris.forEach { uri ->
            processAndDisplayImage(uri)
        }

        Toast.makeText(this, "${imageUris.size} images received", Toast.LENGTH_SHORT).show()
    }

    private fun extractUrls(text: String): List<String> {
        val urls = mutableListOf<String>()
        val matcher = Patterns.WEB_URL.matcher(text)
        while (matcher.find()) {
            val url = matcher.group()
            if (url != null) {
                urls.add(url)
            }
        }
        return urls
    }

    private fun processUrls(urls: List<String>) {
