    private fun processAndDisplayImage(uri: Uri) {
        try {
            val inputStream: InputStream? = contentResolver.openInputStream(uri)
            inputStream?.use { stream ->
                val bitmap = BitmapFactory.decodeStream(stream)
                if (bitmap != null) {
                    Log.d(TAG, "Image decoded: ${bitmap.width}x${bitmap.height}")

                    val imageView = ImageView(this).apply {
                        setImageBitmap(bitmap)
                        adjustViewBounds = true
                        val params = LinearLayout.LayoutParams(
                            LinearLayout.LayoutParams.MATCH_PARENT,
                            LinearLayout.LayoutParams.WRAP_CONTENT
                        )
                        params.setMargins(0, 16, 0, 16)
                        layoutParams = params
                        scaleType = ImageView.ScaleType.FIT_CENTER
                    }

                    val infoView = TextView(this).apply {
                        text = "Size: ${bitmap.width}x${bitmap.height} | URI: $uri"
                        textSize = 12f
                        setPadding(0, 0, 0, 24)
                    }

                    imageContainer.addView(imageView)
                    imageContainer.addView(infoView)

                    processImage(uri, bitmap.width, bitmap.height)
                } else {
                    showError("Failed to decode image from URI: $uri")
                }
            } ?: run {
                showError("Could not open input stream for URI: $uri")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error processing image", e)
            showError("Error processing image: ${e.message}")
        }
    }

    private fun processImage(uri: Uri, width: Int, height: Int) {
        Log.d(TAG, "Processing image - URI: $uri, Dimensions: ${width}x${height}")

        // Retrieve MIME type
        val mimeType = contentResolver.getType(uri)
        Log.d(TAG, "Image MIME type: $mimeType")

