        // - Apply filters
        // - Extract EXIF data
        // - Generate thumbnails
    }

    private fun showError(message: String) {
        Log.e(TAG, message)
        statusTextView.text = "Error"
        contentTextView.text = message
        Toast.makeText(this, message, Toast.LENGTH_LONG).show()
    }
